#!/usr/bin/env python3
"""
ollama_mcp_server.py

A Model Context Protocol (MCP) server that bridges Ollama models into an IDE.
Implements 6 tools for health checking, listing, chatting, generating, showing, and pulling models.

Generated by: Qwen 3.5 397B (Ollama Cloud)
Audited by:   Qwen 3.5 397B (self-audit)
Hardened by:  Antigravity IDE agent (fixes #2,#3,#4,#5,#8,#9,#11)
"""

import os
import sys
import glob
import json
import asyncio
import logging

# ── VENV BOOTSTRAP ──────────────────────────────────────────────
# When executed by Glama's auto-generated Docker template, bare `python`
# resolves to the global interpreter while `uv sync` installs packages
# into /app/.venv. This bootstrap detects that situation and adds the
# venv site-packages to sys.path before any third-party imports.
_script_dir = os.path.dirname(os.path.abspath(__file__))
_venv_sp = glob.glob(os.path.join(_script_dir, ".venv", "lib", "python*", "site-packages"))
if _venv_sp and _venv_sp[0] not in sys.path:
    sys.path.insert(0, _venv_sp[0])

import httpx
from typing import Any

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool, TextContent, ToolAnnotations

# ── CONFIG ──────────────────────────────────────────────────────
OLLAMA_HOST = os.getenv("OLLAMA_HOST", "http://localhost:11434")
REQUEST_TIMEOUT = float(os.getenv("OLLAMA_TIMEOUT", "300"))

# ── LOGGING (#8 fix) ───────────────────────────────────────────
logging.basicConfig(level=logging.INFO, format="%(asctime)s [%(name)s] %(levelname)s: %(message)s")
log = logging.getLogger("ollama-mcp")

# ── HTTP CLIENT (#5 fix: singleton, #4 fix: no redirects) ─────
_client = httpx.AsyncClient(
    base_url=OLLAMA_HOST,
    timeout=httpx.Timeout(REQUEST_TIMEOUT, connect=10.0),
    follow_redirects=False,
)

# Initialize Server
app = Server("ollama")

# ── HELPERS ─────────────────────────────────────────────────────

def _build_options(arguments: dict) -> dict:
    """Extract Ollama options from MCP arguments. (#9 fix: DRY)"""
    options = {}
    if "temperature" in arguments:
        options["temperature"] = arguments["temperature"]
    max_tokens = arguments.get("max_tokens")
    if max_tokens is not None and max_tokens > 0:
        options["num_predict"] = max_tokens
    return options


def _safe_json(resp: httpx.Response) -> dict:
    """Parse JSON response safely. (#3 fix: handle non-JSON)"""
    try:
        return resp.json()
    except (json.JSONDecodeError, ValueError):
        return {"error": "Invalid JSON from Ollama", "raw": resp.text[:500]}


def _validate_required(arguments: dict, *keys: str) -> str | None:
    """Validate required arguments exist. (#2 fix: no KeyError)"""
    for key in keys:
        if key not in arguments or arguments[key] is None:
            return f"Missing required argument: '{key}'"
    return None


def _error(message: str, **extra) -> list[TextContent]:
    """Return a structured error response. (#11 fix: sanitized)"""
    payload = {"error": message}
    payload.update(extra)
    return [TextContent(type="text", text=json.dumps(payload, indent=2))]


def _ok(data: Any) -> list[TextContent]:
    """Return a structured success response."""
    return [TextContent(type="text", text=json.dumps(data, indent=2, default=str))]


