# ── SERVER LOGIC ────────────────────────────────────────────────

@app.list_tools()
async def list_tools() -> list[Tool]:
    return TOOLS


@app.call_tool()
async def call_tool(name: str, arguments: dict[str, Any]) -> list[TextContent]:
    """Dispatches tool calls to the appropriate Ollama API endpoint."""
    log.info(f"Tool call: {name} | model={arguments.get('model', 'n/a')}")

    try:
        # ── ollama_health ───────────────────────────────────
        if name == "ollama_health":
            root_resp = await _client.get("/")
            connected = root_resp.status_code == 200

            ps_data = {}
            try:
                ps_resp = await _client.get("/api/ps")
                ps_data = _safe_json(ps_resp)
            except Exception:
                pass

            return _ok({
                "connected": connected,
                "host": OLLAMA_HOST,
                "running_models": ps_data.get("models", [])
            })

        # ── ollama_list_models ──────────────────────────────
        elif name == "ollama_list_models":
            tags_resp = await _client.get("/api/tags")
            tags_data = _safe_json(tags_resp)

            ps_resp = await _client.get("/api/ps")
            ps_data = _safe_json(ps_resp)

            running_names = {m["name"] for m in ps_data.get("models", [])}

            models_list = []
            for model in tags_data.get("models", []):
                models_list.append({
                    "name": model.get("name", "unknown"),
                    "size": model.get("size"),
                    "modified_at": model.get("modified_at"),
                    "loaded": model.get("name", "") in running_names
                })

            return _ok({"models": models_list})

        # ── ollama_chat ─────────────────────────────────────
        elif name == "ollama_chat":
            err = _validate_required(arguments, "model", "messages")
            if err:
                return _error(err)

            payload = {
                "model": arguments["model"],
                "messages": arguments["messages"],
                "stream": False
            }
            if "system" in arguments:
                payload["messages"] = [
                    {"role": "system", "content": arguments["system"]}
                ] + payload["messages"]

            options = _build_options(arguments)
            if options:
                payload["options"] = options

            resp = await _client.post("/api/chat", json=payload)
            resp.raise_for_status()
            return _ok(_safe_json(resp))

        # ── ollama_generate ─────────────────────────────────
        elif name == "ollama_generate":
            err = _validate_required(arguments, "model", "prompt")
            if err:
                return _error(err)

            payload = {
                "model": arguments["model"],
                "prompt": arguments["prompt"],
                "stream": False
            }
            if "system" in arguments:
                payload["system"] = arguments["system"]

            options = _build_options(arguments)
            if options:
                payload["options"] = options

            resp = await _client.post("/api/generate", json=payload)
            resp.raise_for_status()
            return _ok(_safe_json(resp))

        # ── ollama_show_model ───────────────────────────────
        elif name == "ollama_show_model":
            err = _validate_required(arguments, "model")
            if err:
                return _error(err)

            resp = await _client.post("/api/show", json={"name": arguments["model"]})
            resp.raise_for_status()
            return _ok(_safe_json(resp))

        # ── ollama_pull_model ───────────────────────────────
        elif name == "ollama_pull_model":
            err = _validate_required(arguments, "model")
            if err:
                return _error(err)

            log.info(f"Pulling model: {arguments['model']}")
            resp = await _client.post("/api/pull", json={"name": arguments["model"], "stream": False})
            resp.raise_for_status()
            return _ok(_safe_json(resp))

        # ── unknown tool ────────────────────────────────────
        else:
            return _error(f"Unknown tool: {name}")

    except httpx.ConnectError:
        log.error(f"Connection failed to {OLLAMA_HOST}")
        return _error("Connection Failed", details=f"Could not connect to Ollama at {OLLAMA_HOST}. Is it running?")
    except httpx.TimeoutException:
        log.error(f"Request timed out after {REQUEST_TIMEOUT}s")
        return _error("Timeout", details=f"Request timed out after {REQUEST_TIMEOUT}s. Increase OLLAMA_TIMEOUT env var for cloud models.")
    except httpx.HTTPStatusError as e:
        log.error(f"HTTP {e.response.status_code}: {e.response.text[:200]}")
        return _error("HTTP Error", status_code=e.response.status_code, details=e.response.text[:500])
    except Exception as e:
        log.exception("Unexpected error in tool call")
        return _error("Internal server error")

# ── MAIN ────────────────────────────────────────────────────────

SERVER_INSTRUCTIONS = (
    "Ollama-Omega bridges any Ollama model — local or cloud — into your IDE via MCP. "
    "Recommended workflow: (1) Call ollama_health to verify connection. "
    "(2) Call ollama_list_models to discover available models. "
    "(3) If the needed model is not listed, call ollama_pull_model to download it. "
    "(4) Use ollama_chat for multi-turn conversations or ollama_generate for single-prompt completions. "
    "(5) Use ollama_show_model to inspect model metadata, license, and quantization details. "
    "All tools return structured JSON. Error responses always include an 'error' key with a human-readable message. "
    "The server connects to the Ollama daemon at OLLAMA_HOST (default: http://localhost:11434). "
    "Cloud-hosted models accessible through the same tools if the Ollama daemon supports them."
)


async def main():
    log.info(f"Ollama MCP Server starting | host={OLLAMA_HOST} timeout={REQUEST_TIMEOUT}s")
    async with stdio_server() as (read, write):
        init_options = app.create_initialization_options()
        init_options.instructions = SERVER_INSTRUCTIONS
        await app.run(read, write, init_options)


if __name__ == "__main__":
    asyncio.run(main())
